 10→import formatPostDate from "../../../helpers/formatDateString";
 11→
 12→const incrementReplyCount = (old, parentId) => {
 13→    if (!old || !Array.isArray(old.pages)) return old;
 14→
 15→    return {
 16→        ...old,
 17→        pages: old.pages.map((page) => ({
 18→            ...page,
 19→            comments: Array.isArray(page?.comments)
 20→                ? page.comments.map((comment) => {
 21→                    if (comment?.id !== parentId) return comment;
 22→                    return {
 23→                        ...comment,
 24→                        reply_count: (comment?.reply_count || 0) + 1,
 25→                    };
 26→                })
 27→                : page?.comments,
 28→        })),
 29→    };
 30→};
