 99→                id: user?.userData?.[0]?.id,
100→                name: user?.userData?.[0]?.name,
101→                image_url: user?.userData?.[0]?.image_url,
102→                badge: user?.userData?.[0]?.badge,
103→            },
104→        };
105→
106→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
107→        const previousComments = queryClient.getQueryData(['postComments', postId]);
108→        const previousJournalCaches = [
109→            ...queryClient.getQueriesData({ queryKey: ['journals'] }),
