    padding: 60px 0;
}

.chapter-reader-error {
    text-align: center;
    color: var(--text-secondary);
    padding: 40px 0;
}

/* Progress bar */
.chapter-progress-track {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--border-light);
    z-index: 100;
}

.chapter-progress-fill {
    height: 100%;
    width: 0;
    background: var(--accent-purple);
    transition: width 0.1s linear;
}

/* Header */
.chapter-reader-header {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 20px 0 16px;
    border-bottom: 1px solid var(--border-light);
    margin-bottom: 24px;
}

.chapter-reader-back {
    width: 36px;
    height: 36px;
    border: none;
    background: var(--bg-secondary);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background-color 0.12s ease;
    flex-shrink: 0;
    margin-top: 2px;
}

.chapter-reader-back:hover {
    background: var(--bg-hover);
}

.chapter-reader-header-info {
    min-width: 0;
}

.chapter-reader-chapter-label {
    font-size: 0.75rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 500;
}

.chapter-reader-title {
    font-size: 1.3rem;
    font-weight: 700;
    color: var(--text-primary);
    margin: 4px 0 0 0;
    line-height: 1.25;
}

/* Content */
.chapter-reader-body {
    min-height: 300px;
    position: relative;
}

.chapter-reader-content {
    font-size: 1.05rem;
    line-height: 1.85;
    color: var(--text-primary);
    outline: none;
}

.chapter-reader-content .editor-paragraph {
    margin-bottom: 1em;
}

/* Navigation */
.chapter-reader-nav {
    display: flex;
    justify-content: space-between;
    align-items: stretch;
    gap: 12px;
    margin-top: 40px;
    padding-top: 20px;
    border-top: 1px solid var(--border-light);
}

.chapter-nav-btn {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 12px 16px;
    border: 1px solid var(--border-light);
    border-radius: 10px;
    background: none;
    color: var(--text-secondary);
    font-size: 0.82rem;
    cursor: pointer;
    transition: background-color 0.12s ease;
    max-width: 48%;
}

.chapter-nav-btn:hover {
    background: var(--bg-hover);
}

.chapter-nav-btn span {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.chapter-nav-prev {
    text-align: left;
}

.chapter-nav-next {
    text-align: right;
    margin-left: auto;
}

@media (max-width: 480px) {
    .chapter-reader {
        padding: 0 12px 32px;
        padding-bottom: 5rem;
    }

    .chapter-reader-title {
        font-size: 1.1rem;
    }

    .chapter-reader-content {
        font-size: 0.98rem;
        line-height: 1.75;
    }

    .chapter-nav-btn {
        padding: 10px 12px;
        font-size: 0.78rem;
    }
}

/* ─── Paragraph Comment Layer (pcl-) ─── */

.pcl-layer {
    position: absolute;
    top: 0;
    right: -44px;
    width: 36px;
    height: 100%;
    pointer-events: none;
}

.pcl-row {
    position: absolute;
    right: 0;
    width: 36px;
    display: flex;
    align-items: flex-start;
    justify-content: center;
    padding-top: 2px;
    pointer-events: auto;
}

.pcl-badge {
    display: flex;
    align-items: center;
    gap: 3px;
    padding: 4px 6px;
    border: 1px solid var(--border-light);
    border-radius: 8px;
    background: var(--bg-glass, var(--bg-secondary));
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    color: var(--text-muted);
    cursor: pointer;
    font-size: 0.7rem;
    font-weight: 600;
    white-space: nowrap;
    transition: border-color 0.15s ease, color 0.15s ease, box-shadow 0.15s ease;
}

.pcl-badge:hover {
    border-color: var(--accent-amber);
    color: var(--accent-amber);
    box-shadow: 0 0 8px rgba(245, 158, 11, 0.15);
}

.pcl-badge-active {
    color: var(--accent-amber);
    border-color: var(--accent-amber);
}

.pcl-badge-active:hover {
    box-shadow: 0 0 10px rgba(245, 158, 11, 0.2);
}

.pcl-badge-count {
    line-height: 1;
}

@media (max-width: 768px) {
    .pcl-layer {
        right: -6px;
        width: 28px;
    }

    .pcl-row {
        width: 28px;
    }

    .pcl-badge {
        padding: 3px 4px;
        border-radius: 6px;
    }

    .pcl-badge-count {
        font-size: 0.65rem;
    }
}

/* ─── Comment Panel (cp-) ─── */

.cp-backdrop {
    position: fixed;
    inset: 0;
    background: var(--bg-overlay, rgba(0, 0, 0, 0.4));
    backdrop-filter: blur(2px);
    -webkit-backdrop-filter: blur(2px);
    z-index: 200;
}

.cp-panel {
    display: flex;
    flex-direction: column;
    background: var(--bg-elevated, var(--bg-primary));
    z-index: 201;
    overflow: hidden;
}

.cp-panel-desktop {
    position: fixed;
    top: 0;
    right: 0;
    width: 380px;
    height: 100%;
    border-left: 1px solid var(--border-light);
}

.cp-panel-mobile {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    height: 70vh;
    border-radius: 16px 16px 0 0;
    border-top: 1px solid var(--border-light);
}

.cp-drag-handle {
    width: 36px;
    height: 4px;
    border-radius: 2px;
    background: var(--text-muted);
    opacity: 0.4;
    margin: 8px auto 0;
    flex-shrink: 0;
}

.cp-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 16px 12px;
    border-bottom: 1px solid var(--border-light);
    flex-shrink: 0;
}

.cp-title {
    font-family: var(--font-ui, sans-serif);
    font-size: 0.9rem;
    font-weight: 700;
    color: var(--text-primary);
    margin: 0;
}

.cp-close {
    width: 30px;
    height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    border-radius: 6px;
    transition: background-color 0.12s ease, color 0.12s ease;
}

.cp-close:hover {
    background: var(--bg-hover);
    color: var(--text-primary);
}

.cp-preview {
    display: flex;
    gap: 10px;
    padding: 12px 16px;
    background: var(--bg-selection, var(--bg-secondary));
    flex-shrink: 0;
}

.cp-preview-bar {
    width: 3px;
    min-height: 100%;
    border-radius: 2px;
    background: var(--accent-amber);
    flex-shrink: 0;
}

.cp-preview-text {
    font-family: var(--font-serif, Georgia, serif);
    font-size: 0.82rem;
    line-height: 1.5;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.cp-list {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
    scrollbar-width: thin;
    scrollbar-color: var(--border-light) transparent;
}

.cp-list::-webkit-scrollbar {
    width: 4px;
}

.cp-list::-webkit-scrollbar-thumb {
    background: var(--border-light);
    border-radius: 2px;
}

.cp-loading {
