    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    border-radius: 6px;
    transition: background-color 0.12s ease, color 0.12s ease;
}

.cp-close:hover {
    background: var(--bg-hover);
    color: var(--text-primary);
}

.cp-preview {
    display: flex;
    gap: 10px;
    padding: 12px 16px;
    background: var(--bg-selection, var(--bg-secondary));
    flex-shrink: 0;
}

.cp-preview-bar {
    width: 3px;
    min-height: 100%;
    border-radius: 2px;
    background: var(--accent-amber);
    flex-shrink: 0;
}

.cp-preview-text {
    font-family: var(--font-serif, Georgia, serif);
    font-size: 0.82rem;
    line-height: 1.5;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.cp-list {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
    scrollbar-width: thin;
    scrollbar-color: var(--border-light) transparent;
}

.cp-list::-webkit-scrollbar {
    width: 4px;
}

.cp-list::-webkit-scrollbar-thumb {
    background: var(--border-light);
    border-radius: 2px;
}

.cp-loading {
    display: flex;
    justify-content: center;
    padding: 32px 0;
}

.cp-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 40px 20px;
    text-align: center;
}

.cp-empty p {
    color: var(--text-secondary);
    font-size: 0.85rem;
    margin: 4px 0 0;
}

.cp-empty span {
    color: var(--text-muted);
    font-size: 0.78rem;
}

.cp-input-area {
    border-top: 1px solid var(--border-light);
    padding: 10px 14px 12px;
    flex-shrink: 0;
}

.cp-reply-indicator {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 8px 6px;
    font-size: 0.75rem;
    color: var(--accent-amber);
}

.cp-reply-indicator button {
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    padding: 2px;
    display: flex;
    align-items: center;
}

.cp-reply-indicator button:hover {
    color: var(--text-primary);
}

.cp-input-row {
    display: flex;
    gap: 8px;
    align-items: flex-end;
}

.cp-textarea {
    flex: 1;
    padding: 8px 12px;
    border: 1px solid var(--border-light);
    border-radius: 10px;
    background: var(--bg-pill, var(--bg-secondary));
    color: var(--text-primary);
    font-size: 0.82rem;
    font-family: inherit;
    resize: none;
    outline: none;
    min-height: 36px;
    max-height: 80px;
    transition: border-color 0.15s ease;
}

.cp-textarea:focus {
    border-color: var(--accent-amber);
}

.cp-textarea::placeholder {
    color: var(--text-muted);
}

.cp-submit {
    padding: 8px 16px;
    border: none;
    border-radius: 10px;
    background: var(--accent-amber);
    color: #fff;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: opacity 0.12s ease;
    flex-shrink: 0;
}

.cp-submit:disabled {
    opacity: 0.4;
    cursor: default;
}

.cp-submit:not(:disabled):hover {
    opacity: 0.9;
}

.cp-char-count {
    display: block;
    text-align: right;
    font-size: 0.68rem;
    color: var(--text-muted);
    margin-top: 4px;
}

.cp-char-warn {
    color: var(--accent-amber);
}

.cp-char-red {
    color: var(--accent-red, #ef4444);
}

/* ─── Chapter Comment Card (ccc-) ─── */

.ccc-card {
    padding: 12px 16px;
    border-bottom: 1px solid var(--border-light);
}

.ccc-reply {
    margin-left: 20px;
    position: relative;
    border-bottom: none;
    padding: 8px 12px;
}

.ccc-thread-line {
    position: absolute;
    left: -10px;
    top: 0;
    bottom: 0;
    width: 2px;
    background: var(--border-light);
    border-radius: 1px;
}

.ccc-content {
    min-width: 0;
}

.ccc-user-row {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 4px;
}

.ccc-avatar-wrap {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    overflow: hidden;
    flex-shrink: 0;
    cursor: pointer;
    border: 1.5px solid transparent;
}

.ccc-ring-legend {
    border-color: #FFD700;
}

.ccc-ring-og {
    border-color: #9B59FF;
}

.ccc-avatar {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.ccc-name {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-primary);
    cursor: pointer;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 140px;
}

.ccc-name:hover {
    text-decoration: underline;
}

.ccc-dot {
    color: var(--text-muted);
    font-size: 0.7rem;
}

.ccc-date {
    font-size: 0.7rem;
    color: var(--text-muted);
    white-space: nowrap;
}

.ccc-body {
    font-family: var(--font-serif, Georgia, serif);
    font-size: 0.84rem;
    line-height: 1.55;
    color: var(--text-primary);
    margin: 0 0 6px;
    word-break: break-word;
}

.ccc-actions {
    display: flex;
    gap: 8px;
}

.ccc-action-btn {
    display: flex;
    align-items: center;
    gap: 4px;
    border: none;
    background: none;
    color: var(--text-muted);
    font-size: 0.72rem;
    cursor: pointer;
    padding: 3px 8px;
    border-radius: 6px;
    transition: background-color 0.12s ease, color 0.12s ease;
}

.ccc-action-btn:hover {
    background: var(--bg-hover);
    color: var(--accent-amber);
}

.ccc-replies {
    overflow: hidden;
}

