/* ── Comment Section Container ── */
.cm-parent-container {
    position: absolute;
    display: flex;
    flex-direction: column;
    top: 200px;
    width: 90%;
    height: 60%;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    z-index: 4;
    overflow: hidden;
}

/* ── Header ── */
.cm-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
    flex-shrink: 0;
}
.cm-header-title {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-heading);
    margin: 0;
    padding: 0;
}
.cm-close-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    cursor: pointer;
    transition: background-color 0.15s ease;
}
.cm-close-btn:hover {
    background-color: var(--bg-pill);
}
.cm-close-btn svg {
    fill: var(--text-faint);
    width: 18px;
    height: 18px;
    transition: fill 0.15s ease;
}
.cm-close-btn:hover svg {
    fill: var(--text-heading);
}

/* ── Comment list ── */
.cm-list {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    padding: 0.75rem 1.15rem;
    gap: 0.25rem;
}
.cm-list::-webkit-scrollbar {
    width: 5px;
}
.cm-list::-webkit-scrollbar-thumb {
    background: var(--accent-amber);
    border-radius: 4px;
}
.cm-list::-webkit-scrollbar-track {
    background-color: var(--bg-pill);
}

/* ── Loading ── */
.cm-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100%;
    width: 100%;
}

/* ── See more button ── */
.cm-load-more {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.4rem;
    cursor: pointer;
    background: none;
    border: 1px solid var(--border-card);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    margin-top: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: background-color 0.15s ease;
}
.cm-load-more:hover {
    background-color: var(--bg-pill);
}

/* ── Input area ── */
.cm-input-area {
    display: flex;
    flex-direction: column;
    padding: 0.75rem 1.15rem;
    border-top: 1px solid var(--border-card);
    gap: 0.5rem;
    flex-shrink: 0;
}
.cm-input-row {
    display: flex;
    align-items: flex-end;
    gap: 0.75rem;
}
.cm-textarea {
    flex: 1;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    background-color: var(--bg-pill);
    color: var(--text-primary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    padding: 0.55rem 0.75rem;
    resize: none;
    min-height: 1.4rem;
    max-height: 80px;
    overflow-y: auto;
    transition: border-color 0.2s ease;
}
.cm-textarea:focus {
    outline: none;
    border-color: var(--accent-amber);
}
.cm-textarea::placeholder {
    color: var(--text-faint);
    font-style: italic;
}
.cm-action-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}
.cm-char-count {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 500;
    color: var(--text-faint);
    margin: 0;
    padding: 0;
    transition: color 0.15s ease;
}
.cm-char-count.cm-char-limit {
    color: rgb(255, 80, 80);
    font-weight: 650;
}
.cm-submit-btn {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1.1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.cm-submit-btn:hover {
    opacity: 0.88;
}
.cm-submit-btn:disabled {
    cursor: default;
    opacity: 0.45;
}

/* ── Progress bar wrapper ── */
.cm-progress {
    flex-shrink: 0;
}

/* ── Comment Card ── */
.cm-card {
    position: relative;
    display: flex;
    align-items: stretch;
    padding: 0.65rem 0;
    border-bottom: 1px solid var(--border-card);
}
.cm-card:last-child {
    border-bottom: none;
}

/* Thread line for nested replies */
.cm-thread-line {
    position: absolute;
    left: -0.65rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    transition: background-color 0.2s ease;
}
.cm-card:hover > .cm-thread-line {
    background-color: var(--accent-amber);
}

.cm-card-content {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    flex: 1;
    min-width: 0;
}

/* ── User row ── */
.cm-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.cm-avatar-container {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    cursor: pointer;
}
.cm-avatar-container.cm-ring-legend {
    border: 2px solid #FFD700;
    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
}
.cm-avatar-container.cm-ring-og {
    border: 2px solid #9B59FF;
    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
}
.cm-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
    cursor: pointer;
    user-select: none;
}
.cm-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
    cursor: pointer;
    transition: color 0.15s ease;
}
.cm-username:hover {
    color: var(--accent-amber);
    text-decoration: underline;
}
.cm-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.cm-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

/* ── Comment body ── */
.cm-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
    margin: 0;
    padding: 0;
}

/* ── Action row ── */
.cm-card-actions {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding-top: 0.15rem;
}
.cm-reply-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.2rem 0.4rem;
    border-radius: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease, background-color 0.15s ease;
}
.cm-reply-btn:hover {
    color: var(--accent-amber);
    background-color: var(--bg-pill);
}

.cm-toggle-replies-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.2rem 0.4rem;
    border-radius: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease, background-color 0.15s ease;
}
.cm-toggle-replies-btn:hover {
    color: var(--accent-amber);
    background-color: var(--bg-pill);
}

/* ── Reply input ── */
.cm-reply-input-wrapper {
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
    overflow: hidden;
    padding-top: 0.25rem;
}
.cm-reply-textarea {
    flex: 1;
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: italic;
    background-color: var(--bg-pill);
    color: var(--text-primary);
    border: 1px solid var(--border-card);
    border-radius: 8px;
    padding: 0.45rem 0.65rem;
    resize: none;
    min-height: 1.2rem;
    transition: border-color 0.2s ease;
}
.cm-reply-textarea:focus {
    outline: none;
    border-color: var(--accent-amber);
}
.cm-reply-textarea::placeholder {
    color: var(--text-faint);
}
.cm-reply-action-row {
    display: flex;
    gap: 0.5rem;
    align-items: center;
    justify-content: flex-end;
}
.cm-reply-char-count {
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 500;
    color: var(--text-faint);
    margin: 0;
    padding: 0;
}
.cm-reply-char-count.cm-char-limit {
    color: rgb(255, 80, 80);
    font-weight: 650;
}
.cm-reply-submit-btn {
    cursor: pointer;
    border: none;
    padding: 0.3rem 0.9rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.cm-reply-submit-btn:hover {
    opacity: 0.88;
}

/* ── Reply loading ── */
.cm-reply-loading {
    display: flex;
    align-items: center;
    padding-left: 0.25rem;
}

/* ── Nested replies container ── */
.cm-replies-thread {
    padding-left: 1.25rem;
}

/* ── Show more replies ── */
.cm-show-more-replies {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    background: none;
    border: 1px solid var(--border-card);
    border-radius: 20px;
    padding: 0.3rem 0.85rem;
    margin-top: 0.4rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: background-color 0.15s ease;
}
.cm-show-more-replies:hover {
    background-color: var(--bg-pill);
}

/* ── Mobile responsive ── */
@media (max-width: 480px) {
    .cm-parent-container {
        position: absolute;
        top: 200px;
        width: 92%;
        height: 60%;
        border-radius: 12px;
        z-index: 134;
    }
    .cm-header {
        padding: 0.6rem 0.75rem;
    }
    .cm-header-title {
        font-size: 0.82rem;
    }
    .cm-list {
        padding: 0.6rem 0.75rem;
    }
    .cm-input-area {
        padding: 0.6rem 0.75rem;
    }
    .cm-avatar {
        width: 18px;
        height: 18px;
    }
    .cm-username {
        font-size: 0.74rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .cm-body {
        font-size: 0.8rem;
        line-height: 1.55;
    }
    .cm-date {
        font-size: 0.65rem;
    }
    .cm-reply-btn,
    .cm-toggle-replies-btn {
        font-size: 0.68rem;
    }
    .cm-textarea {
        font-size: 0.8rem;
    }
    .cm-submit-btn {
        font-size: 0.72rem;
        padding: 0.3rem 0.9rem;
    }
    .cm-replies-thread {
        padding-left: 0.75rem;
    }
    .cm-reply-textarea {
        font-size: 0.78rem;
    }
    .cm-reply-submit-btn {
        font-size: 0.68rem;
        padding: 0.25rem 0.7rem;
    }
}

@media (max-width: 428px) {
    .cm-parent-container {
        width: 340px;
    }
}

