  1→import { useState, useEffect, useCallback, useRef } from 'react';
  2→import { motion } from 'framer-motion';
  3→
  4→const CommentBadge = ({ count, onClick, hasComments }) => {
  5→    return (
  6→        <motion.button
  7→            className={`pcl-badge ${hasComments ? 'pcl-badge-active' : ''}`}
  8→            onClick={(e) => { e.stopPropagation(); onClick(); }}
  9→            initial={{ opacity: 0, scale: 0.8 }}
 10→            animate={{ opacity: 1, scale: 1 }}
 11→            transition={{ duration: 0.15 }}
 12→        >
 13→            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 14→                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 15→            </svg>
 16→            {hasComments && <span className="pcl-badge-count">{count}</span>}
 17→        </motion.button>
 18→    );
 19→};
 20→
 21→const ParagraphCommentLayer = ({ containerRef, commentCounts, onParagraphClick }) => {
 22→    const [paragraphs, setParagraphs] = useState([]);
 23→    const [hoveredIndex, setHoveredIndex] = useState(null);
 24→    const listenersRef = useRef([]);
 25→
 26→    const scanParagraphs = useCallback(() => {
 27→        const container = containerRef.current;
 28→        if (!container) return;
 29→
 30→        // Clean up old listeners
 31→        listenersRef.current.forEach(({ el, enter, leave }) => {
 32→            el.removeEventListener('mouseenter', enter);
 33→            el.removeEventListener('mouseleave', leave);
 34→        });
 35→        listenersRef.current = [];
 36→
 37→        const elements = container.querySelectorAll('.editor-paragraph');
 38→        const result = [];
 39→        let realIndex = 0;
 40→
 41→        elements.forEach((el) => {
 42→            const text = el.textContent.trim();
 43→            if (!text) return;
 44→
 45→            const idx = realIndex;
 46→            el.setAttribute('data-paragraph-index', idx);
 47→            const fingerprint = text.substring(0, 100);
 48→
 49→            result.push({
 50→                index: idx,
 51→                top: el.offsetTop,
 52→                height: el.offsetHeight,
 53→                text,
 54→                fingerprint,
 55→            });
 56→
 57→            // Attach hover listeners directly to paragraph DOM elements
 58→            const enter = () => setHoveredIndex(idx);
 59→            const leave = () => setHoveredIndex((prev) => prev === idx ? null : prev);
 60→            el.addEventListener('mouseenter', enter);
 61→            el.addEventListener('mouseleave', leave);
 62→            listenersRef.current.push({ el, enter, leave });
 63→
 64→            realIndex++;
 65→        });
 66→
 67→        setParagraphs(result);
 68→    }, [containerRef]);
 69→
 70→    useEffect(() => {
 71→        const container = containerRef.current;
 72→        if (!container) return;
 73→
 74→        const timer = setTimeout(scanParagraphs, 300);
 75→
 76→        const observer = new MutationObserver(() => {
 77→            scanParagraphs();
 78→        });
 79→
 80→        observer.observe(container, { childList: true, subtree: true, characterData: true });
 81→        window.addEventListener('resize', scanParagraphs);
 82→
 83→        return () => {
 84→            clearTimeout(timer);
 85→            observer.disconnect();
 86→            window.removeEventListener('resize', scanParagraphs);
 87→            // Clean up listeners
 88→            listenersRef.current.forEach(({ el, enter, leave }) => {
 89→                el.removeEventListener('mouseenter', enter);
 90→                el.removeEventListener('mouseleave', leave);
 91→            });
 92→            listenersRef.current = [];
 93→        };
 94→    }, [containerRef, scanParagraphs]);
 95→
 96→    const counts = commentCounts || {};
 97→
 98→    return (
 99→        <div className="pcl-layer">
100→            {paragraphs.map((p) => {
101→                const count = counts[p.index] || 0;
102→                const hasComments = count > 0;
103→                const isHovered = hoveredIndex === p.index;
104→
