                            />
                            <button
                                className="cp-submit"
                                onClick={handleSubmit}
                                disabled={!body.trim() || charCount > MAX_CHARS}
                            >
                                Post
                            </button>
                        </div>
                        <span className={`cp-char-count ${charCount >= 280 ? (charCount >= MAX_CHARS ? 'cp-char-red' : 'cp-char-warn') : ''}`}>
                            {charCount}/{MAX_CHARS}
                        </span>
                    </div>
                )}
            </motion.div>
        </>
    );
};

export default CommentPanel;

