/* ═══════════════════════════════════════════════
   Paragraph Comment Layer (pcl-)
   ═══════════════════════════════════════════════ */

/* Warm paragraph hover — signals commentability */
.chapter-reader-content .editor-paragraph[data-paragraph-index] {
    transition: background-color 0.25s ease;
    border-radius: 3px;
}

.chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
    background-color: var(--bg-selection);
}

.pcl-layer {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    pointer-events: none;
    z-index: 1;
}

.pcl-badge-anchor {
    position: absolute;
    right: 0;
    pointer-events: auto;
    padding-top: 3px;
}

.pcl-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 5px 8px;
    border: 1px solid var(--bg-glass-border);
    border-radius: 20px;
    background: var(--bg-glass);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    color: var(--text-secondary);
    cursor: pointer;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    white-space: nowrap;
    box-shadow: var(--shadow-card-sm);
    transition: color 0.2s ease, border-color 0.2s ease,
                background-color 0.2s ease, box-shadow 0.2s ease,
                transform 0.2s ease;
}

.pcl-badge:hover {
    color: var(--accent-amber);
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection), var(--shadow-card-sm);
    transform: scale(1.06);
}

.pcl-badge-active {
    color: var(--accent-amber);
    border-color: rgba(212, 168, 83, 0.3);
    background: var(--bg-selection);
    box-shadow: 0 0 12px rgba(212, 168, 83, 0.1);
}

.pcl-badge-active:hover {
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection-active),
                0 0 16px rgba(212, 168, 83, 0.14);
}

.pcl-badge svg {
    flex-shrink: 0;
}

.pcl-badge-count {
    line-height: 1;
    min-width: 8px;
    text-align: center;
}

@media (max-width: 768px) {
    .pcl-badge {
        padding: 4px 6px;
        font-size: 0.64rem;
    }

    /* No hover state on touch devices */
    .chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
        background-color: transparent;
    }
}


/* ═══════════════════════════════════════════════
   Comment Panel (cp-)
   ═══════════════════════════════════════════════ */

.cp-backdrop {
    position: fixed;
    inset: 0;
    background: var(--bg-overlay);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    z-index: 200;
}

.cp-panel {
    display: flex;
    flex-direction: column;
    background: var(--bg-card);
    z-index: 201;
    overflow: hidden;
    box-shadow: var(--shadow-modal);
}

.cp-panel-desktop {
    position: fixed;
    top: 0;
    right: 0;
    width: 380px;
    height: 100%;
    border-left: 1px solid var(--border-card);
}

.cp-panel-mobile {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    height: 70vh;
    border-radius: 16px 16px 0 0;
    border-top: 1px solid var(--border-card);
}

.cp-drag-handle {
    width: 36px;
    height: 4px;
    border-radius: 2px;
    background: var(--text-faint);
    margin: 10px auto 0;
    flex-shrink: 0;
}

/* ── Header ── */
.cp-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
    flex-shrink: 0;
}

.cp-header-left {
    display: flex;
    align-items: center;
    gap: 8px;
}

.cp-title {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-heading);
    margin: 0;
}

.cp-count {
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 600;
    color: var(--accent-amber);
    background: var(--bg-selection);
    padding: 2px 7px;
    border-radius: 10px;
    line-height: 1.4;
}

.cp-close {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border: none;
    background: none;
    color: var(--text-faint);
    cursor: pointer;
    border-radius: 50%;
    transition: background-color 0.15s ease, color 0.15s ease;
}

.cp-close:hover {
    background: var(--bg-pill);
    color: var(--text-heading);
}

/* ── Paragraph preview ── */
.cp-preview {
    display: flex;
    gap: 12px;
    padding: 14px 1.15rem;
    background: var(--bg-selection);
    flex-shrink: 0;
    border-bottom: 1px solid var(--border-card);
}

.cp-preview-bar {
    width: 3px;
    min-height: 100%;
    border-radius: 2px;
    background: var(--accent-amber);
    flex-shrink: 0;
}

.cp-preview-text {
    font-family: var(--font-serif);
    font-size: 0.82rem;
    font-style: italic;
    line-height: 1.6;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

/* ── Comment list ── */
.cp-list {
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    padding: 0.5rem 0;
}

.cp-list::-webkit-scrollbar {
    width: 5px;
}

.cp-list::-webkit-scrollbar-thumb {
    background: var(--accent-amber);
    border-radius: 4px;
}

.cp-list::-webkit-scrollbar-track {
    background: var(--bg-pill);
}

.cp-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 40px 0;
}

/* ── Empty state ── */
.cp-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 48px 24px;
    text-align: center;
}

.cp-empty-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    background: var(--bg-selection);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 14px;
}

.cp-empty-icon svg {
    color: var(--accent-amber);
    opacity: 0.7;
}

.cp-empty-title {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 0 0 4px;
}

.cp-empty-hint {
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-style: italic;
    color: var(--text-muted);
}

/* ── Input area ── */
.cp-input-area {
    display: flex;
    flex-direction: column;
    padding: 0.75rem 1.15rem;
    border-top: 1px solid var(--border-card);
    gap: 0.45rem;
    flex-shrink: 0;
}

.cp-reply-indicator {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    padding: 3px 10px;
    background: var(--bg-selection);
    border-radius: 20px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    align-self: flex-start;
}

.cp-reply-indicator button {
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    padding: 0;
    margin-left: 2px;
    font-size: 0.88rem;
    line-height: 1;
    transition: color 0.15s ease;
}

.cp-reply-indicator button:hover {
    color: var(--text-heading);
}

.cp-input-row {
    display: flex;
    align-items: flex-end;
    gap: 0.75rem;
}

.cp-textarea {
    flex: 1;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    background-color: var(--bg-pill);
    color: var(--text-primary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    padding: 0.55rem 0.75rem;
    resize: none;
    min-height: 1.4rem;
    max-height: 80px;
    outline: none;
    overflow-y: auto;
    transition: border-color 0.2s ease;
}

.cp-textarea:focus {
    border-color: var(--accent-amber);
}

.cp-textarea::placeholder {
    color: var(--text-faint);
    font-style: italic;
}

.cp-submit {
    cursor: pointer;
    border: none;
    padding: 0.4rem 1.1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    flex-shrink: 0;
    transition: opacity 0.15s ease;
}

.cp-submit:hover {
    opacity: 0.88;
}

.cp-submit:disabled {
    cursor: default;
    opacity: 0.4;
}

.cp-action-row {
    display: flex;
    align-items: center;
    justify-content: flex-end;
}

.cp-char-count {
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 500;
    color: var(--text-faint);
    margin: 0;
    transition: color 0.15s ease;
}

.cp-char-warn {
    color: var(--accent-amber);
    font-weight: 600;
}

.cp-char-red {
    color: var(--color-danger);
    font-weight: 650;
}


/* ═══════════════════════════════════════════════
   Chapter Comment Card (ccc-)
   ═══════════════════════════════════════════════ */

.ccc-card {
    position: relative;
    display: flex;
    align-items: stretch;
    padding: 0.75rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
    transition: background-color 0.15s ease;
}

.ccc-card:last-child {
    border-bottom: none;
}

.ccc-card:hover {
    background-color: var(--bg-pill);
}

.ccc-reply {
    margin-left: 20px;
    position: relative;
    border-bottom: none;
    padding: 0.55rem 1rem;
}

.ccc-reply:hover {
    background-color: transparent;
}

.ccc-thread-line {
    position: absolute;
    left: -0.65rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--border-card);
