toolUseResult.content:
.chapter-reader {
    max-width: 700px;
    margin: 0 auto;
    padding: 0 16px 40px;
}

.chapter-reader-loading {
    display: flex;
    justify-content: center;
    padding: 60px 0;
}

.chapter-reader-error {
    text-align: center;
    color: var(--text-secondary);
    padding: 40px 0;
}

/* Progress bar */
.chapter-progress-track {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--border-light);
    z-index: 100;
}

.chapter-progress-fill {
    height: 100%;
    width: 0;
    background: var(--accent-purple);
    transition: width 0.1s linear;
}

/* Header */
.chapter-reader-header {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 20px 0 16px;
    border-bottom: 1px solid var(--border-light);
    margin-bottom: 24px;
}

.chapter-reader-back {
    width: 36px;
    height: 36px;
    border: none;
    background: var(--bg-secondary);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background-color 0.12s ease;
    flex-shrink: 0;
    margin-top: 2px;
}

.chapter-reader-back:hover {
    background: var(--bg-hover);
}

.chapter-reader-header-info {
    min-width: 0;
}

.chapter-reader-chapter-label {
    font-size: 0.75rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 500;
}

.chapter-reader-title {
    font-size: 1.3rem;
    font-weight: 700;
    color: var(--text-primary);
    margin: 4px 0 0 0;
    line-height: 1.25;
}

/* Content */
.chapter-reader-body {
    min-height: 300px;
    position: relative;
}

.chapter-reader-content {
    font-size: 1.05rem;
    line-height: 1.85;
    color: var(--text-primary);
    outline: none;
}

.chapter-reader-content .editor-paragraph {
    margin-bottom: 1em;
}

/* Navigation */
.chapter-reader-nav {
    display: flex;
    justify-content: space-between;
    align-items: stretch;
    gap: 12px;
    margin-top: 40px;
    padding-top: 20px;
    border-top: 1px solid var(--border-light);
}

.chapter-nav-btn {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 12px 16px;
    border: 1px solid var(--border-light);
    border-radius: 10px;
    background: none;
    color: var(--text-secondary);
    font-size: 0.82rem;
    cursor: pointer;
    transition: background-color 0.12s ease;
    max-width: 48%;
}

.chapter-nav-btn:hover {
    background: var(--bg-hover);
}

.chapter-nav-btn span {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.chapter-nav-prev {
    text-align: left;
}

.chapter-nav-next {
    text-align: right;
    margin-left: auto;
}

@media (max-width: 480px) {
    .chapter-reader {
        padding: 0 12px 32px;
        padding-bottom: 5rem;
    }

    .chapter-reader-title {
        font-size: 1.1rem;
    }

    .chapter-reader-content {
        font-size: 0.98rem;
        line-height: 1.75;
    }

    .chapter-nav-btn {
        padding: 10px 12px;
        font-size: 0.78rem;
    }
}


/* ═══════════════════════════════════════════════
   Paragraph Comment Layer (pcl-)
   ═══════════════════════════════════════════════ */

/* Warm paragraph hover — signals commentability */
.chapter-reader-content .editor-paragraph[data-paragraph-index] {
    transition: background-color 0.25s ease;
    border-radius: 3px;
}

.chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
    background-color: var(--bg-selection);
}

.pcl-layer {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    pointer-events: none;
    z-index: 1;
}

.pcl-badge-anchor {
    position: absolute;
    right: 0;
    pointer-events: auto;
    padding-top: 3px;
}

.pcl-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 5px 8px;
    border: 1px solid var(--bg-glass-border);
    border-radius: 20px;
    background: var(--bg-glass);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    color: var(--text-secondary);
    cursor: pointer;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    white-space: nowrap;
    box-shadow: var(--shadow-card-sm);
    transition: color 0.2s ease, border-color 0.2s ease,
                background-color 0.2s ease, box-shadow 0.2s ease,
                transform 0.2s ease;
}

.pcl-badge:hover {
    color: var(--accent-amber);
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection), var(--shadow-card-sm);
    transform: scale(1.06);
}

.pcl-badge-active {
    color: var(--accent-amber);
    border-color: rgba(212, 168, 83, 0.3);
    background: var(--bg-selection);
    box-shadow: 0 0 12px rgba(212, 168, 83, 0.1);
}

.pcl-badge-active:hover {
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection-active),
                0 0 16px rgba(212, 168, 83, 0.14);
}

.pcl-badge svg {
    flex-shrink: 0;
}

.pcl-badge-count {
    line-height: 1;
    min-width: 8px;
    text-align: center;
}

@media (max-width: 768px) {
    .pcl-badge {
        padding: 4px 6px;
        font-size: 0.64rem;
    }

    /* No hover state on touch devices */
    .chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
        background-color: transparent;
    }
}


/* ═══════════════════════════════════════════════
   Comment Panel (cp-)
   ═══════════════════════════════════════════════ */

.cp-backdrop {
    position: fixed;
    inset: 0;
    background: var(--bg-overlay);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    z-index: 200;
}

.cp-panel {
    display: flex;
    flex-direction: column;
    background: var(--bg-card);
    z-index: 201;
    overflow: hidden;
    box-shadow: var(--shadow-modal);
}

.cp-panel-desktop {
    position: fixed;
    top: 0;
    right: 0;
    width: 380px;
    height: 100%;
    border-left: 1px solid var(--border-card);
}

.cp-panel-mobile {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    height: 70vh;
    border-radius: 16px 16px 0 0;
    border-top: 1px solid var(--border-card);
}

.cp-drag-handle {
    width: 36px;
    height: 4px;
    border-radius: 2px;
    background: var(--text-faint);
    margin: 10px auto 0;
    flex-shrink: 0;
}

/* ── Header ── */
.cp-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
    flex-shrink: 0;
}

.cp-header-left {
    display: flex;
    align-items: center;
    gap: 8px;
}

.cp-title {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-heading);
    margin: 0;
}

.cp-count {
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 600;
    color: var(--accent-amber);
    background: var(--bg-selection);
    padding: 2px 7px;
    border-radius: 10px;
    line-height: 1.4;
}

.cp-close {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border: none;
    background: none;
    color: var(--text-faint);
    cursor: pointer;
    border-radius: 50%;
    transition: background-color 0.15s ease, color 0.15s ease;
}

.cp-close:hover {
    background: var(--bg-pill);
    color: var(--text-heading);
}

/* ── Paragraph preview ── */
.cp-preview {
    display: flex;
    gap: 12px;
    padding: 14px 1.15rem;
    background: var(--bg-selection);
    flex-shrink: 0;
    border-bottom: 1px solid var(--border-card);
}

.cp-preview-bar {
    width: 3px;
    min-height: 100%;
    border-radius: 2px;
    background: var(--accent-amber);
    flex-shrink: 0;
}

.cp-preview-text {
    font-family: var(--font-serif);
    font-size: 0.82rem;
    font-style: italic;
    line-height: 1.6;
    color: var(--text-secondary);
