}

.cp-list::-webkit-scrollbar-track {
    background: var(--bg-pill);
}

.cp-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 40px 0;
}

/* ── Empty state ── */
.cp-empty {
    display: flex;
    flex-direction: column;
