    color: var(--text-heading);
    margin: 0 0 4px;
}

.cp-empty-hint {
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-style: italic;
    color: var(--text-muted);
}

/* ── Input area ── */
.cp-input-area {
    display: flex;
    flex-direction: column;
    padding: 0.75rem 1.15rem;
    border-top: 1px solid var(--border-card);
    gap: 0.45rem;
    flex-shrink: 0;
}

.cp-reply-indicator {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    padding: 3px 10px;
    background: var(--bg-selection);
    border-radius: 20px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    align-self: flex-start;
}

.cp-reply-indicator button {
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    padding: 0;
    margin-left: 2px;
    font-size: 0.88rem;
    line-height: 1;
    transition: color 0.15s ease;
}

.cp-reply-indicator button:hover {
    color: var(--text-heading);
}

.cp-input-row {
    display: flex;
    align-items: flex-end;
    gap: 0.75rem;
}

.cp-textarea {
    flex: 1;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    background-color: var(--bg-pill);
    color: var(--text-primary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    padding: 0.55rem 0.75rem;
    resize: none;
    min-height: 1.4rem;
    max-height: 80px;
    outline: none;
    overflow-y: auto;
    transition: border-color 0.2s ease;
}

.cp-textarea:focus {
    border-color: var(--accent-amber);
}

.cp-textarea::placeholder {
    color: var(--text-faint);
    font-style: italic;
}

.cp-submit {
    cursor: pointer;
    border: none;
    padding: 0.4rem 1.1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    flex-shrink: 0;
    transition: opacity 0.15s ease;
}

.cp-submit:hover {
    opacity: 0.88;
}

.cp-submit:disabled {
    cursor: default;
    opacity: 0.4;
}

.cp-action-row {
    display: flex;
    align-items: center;
    justify-content: flex-end;
}

.cp-char-count {
    font-family: var(--font-ui);
