-- =============================================
-- Stories Feature – Full Schema Migration
-- Run in Supabase SQL Editor
-- =============================================

-- 1. Stories table
CREATE TABLE IF NOT EXISTS stories (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    author_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    description TEXT DEFAULT '',
    cover_url TEXT DEFAULT NULL,
    status TEXT NOT NULL DEFAULT 'ongoing' CHECK (status IN ('ongoing', 'completed', 'hiatus')),
    tags TEXT[] DEFAULT '{}',
    privacy TEXT NOT NULL DEFAULT 'public' CHECK (privacy IN ('public', 'private')),
    read_count INTEGER NOT NULL DEFAULT 0,
    vote_count INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_stories_author ON stories(author_id);
CREATE INDEX IF NOT EXISTS idx_stories_status ON stories(status);
CREATE INDEX IF NOT EXISTS idx_stories_privacy ON stories(privacy);
CREATE INDEX IF NOT EXISTS idx_stories_created ON stories(created_at DESC);

-- 2. Chapters table
CREATE TABLE IF NOT EXISTS chapters (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    story_id UUID NOT NULL REFERENCES stories(id) ON DELETE CASCADE,
    chapter_number INTEGER NOT NULL,
    title TEXT NOT NULL DEFAULT 'Untitled Chapter',
    content JSONB DEFAULT NULL,
    word_count INTEGER NOT NULL DEFAULT 0,
    status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'published')),
    published_at TIMESTAMPTZ DEFAULT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE(story_id, chapter_number)
);

CREATE INDEX IF NOT EXISTS idx_chapters_story ON chapters(story_id);
CREATE INDEX IF NOT EXISTS idx_chapters_status ON chapters(status);

-- 3. Story comments (paragraph-level)
CREATE TABLE IF NOT EXISTS story_comments (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    chapter_id UUID NOT NULL REFERENCES chapters(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    parent_id UUID DEFAULT NULL REFERENCES story_comments(id) ON DELETE CASCADE,
    comment TEXT NOT NULL,
    paragraph_index INTEGER NOT NULL DEFAULT -1,
    paragraph_fingerprint TEXT DEFAULT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_story_comments_chapter ON story_comments(chapter_id);
CREATE INDEX IF NOT EXISTS idx_story_comments_paragraph ON story_comments(chapter_id, paragraph_index);
CREATE INDEX IF NOT EXISTS idx_story_comments_parent ON story_comments(parent_id);

-- 4. Story votes
CREATE TABLE IF NOT EXISTS story_votes (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    story_id UUID NOT NULL REFERENCES stories(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE(story_id, user_id)
);

CREATE INDEX IF NOT EXISTS idx_story_votes_story ON story_votes(story_id);
CREATE INDEX IF NOT EXISTS idx_story_votes_user ON story_votes(user_id);

-- 5. Reading progress
CREATE TABLE IF NOT EXISTS reading_progress (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    story_id UUID NOT NULL REFERENCES stories(id) ON DELETE CASCADE,
    chapter_id UUID NOT NULL REFERENCES chapters(id) ON DELETE CASCADE,
    scroll_position REAL DEFAULT 0,
    last_read_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE(user_id, story_id)
);

CREATE INDEX IF NOT EXISTS idx_reading_progress_user ON reading_progress(user_id);

-- 6. Story library (reading list / bookmarks)
CREATE TABLE IF NOT EXISTS story_library (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    story_id UUID NOT NULL REFERENCES stories(id) ON DELETE CASCADE,
    added_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE(user_id, story_id)
);

CREATE INDEX IF NOT EXISTS idx_story_library_user ON story_library(user_id);

-- 7. Auto-update triggers for updated_at
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_stories_updated_at ON stories;
CREATE TRIGGER trigger_stories_updated_at
    BEFORE UPDATE ON stories
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS trigger_chapters_updated_at ON chapters;
CREATE TRIGGER trigger_chapters_updated_at
    BEFORE UPDATE ON chapters
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

message.content:
This session is being continued from a previous conversation that ran out of context. The summary below covers the earlier portion of the conversation.

Analysis:
Let me chronologically analyze the conversation:

1. **Initial Plan Implementation**: User provided a detailed plan for implementing paragraph-level comments for a Chapter Reader in their iskrib_v3 project. The plan specified what already exists (DB, backend, client API) and what needs to be built (frontend UI).

2. **Step 1-2: Hooks**: Added query hooks (`useChapterCommentCounts`, `useChapterComments`) to `useStoryData.js` and mutation hook (`useAddChapterComment`) to `useStoryMutations.js`.

3. **Step 3: ParagraphCommentLayer**: Created component with MutationObserver to detect Lexical paragraphs and show comment badges. Initially had a bug where `onMouseLeave` set `hovered` to `true` instead of `false`.

4. **Step 4: ChapterCommentCard**: Created individual comment display component following existing `commentsCards.jsx` patterns.

5. **Step 5: CommentPanel**: Created slide-in panel with desktop/mobile variants, optimistic updates.

6. **Step 6: ChapterReader Integration**: Modified to add ref, state, hooks, and render new components.

7. **Step 7: CSS Styles**: Added all pcl-, cp-, ccc- prefixed styles.

8. **User Issue 1**: "how to add comments on paragraph? when i hover onto paragraph theres not comment icon to click" - The badge was positioned 44px outside the right margin in a tiny invisible strip. Fixed by attaching hover listeners directly to paragraph DOM elements and positioning badges within content bounds.

9. **User Issue 2**: "can you use /frontend-design to make it elegant and delightful and make sure it is visible during darkmode" - Used frontend-design skill. Thoroughly researched the design system (CSS variables, light/dark themes, existing comment patterns). Redesigned all three components matching the warm literary aesthetic with Lora serif + Outfit sans-serif, amber accents, glass morphism badges, editorial blockquote preview, avatar ring glows, etc.

10. **User Issue 3**: "why if i hove on the comment icon it disappears" - Badge disappeared because moving from paragraph to badge triggered `mouseleave` on the paragraph, unmounting the badge. Fixed with 150ms debounce timer using `leaveTimerRef` - paragraph mouseleave schedules delayed removal, badge anchor mouseenter cancels the timer.

11. **User Issue 4**: Supabase error "Could not find a relationship between 'story_comments' and 'users'" - The `story_comments.user_id` referenced `auth.users(id)` but PostgREST needs FK to `public.users(id)`. Provided SQL migration to add the FK. Also found and fixed field name mismatch: frontend sent `body` but backend expects `comment`.

12. **User Issue 5 (CURRENT)**: "also the comment icon is flickering when i hove on it, i cant click it" - The 150ms debounce still isn't enough. The badge unmounts/remounts causing flicker. The user reported this right before the summary was requested.

Key files involved:
- `client/src/components/Stories/hooks/useStoryData.js` - Modified
- `client/src/components/Stories/hooks/useStoryMutations.js` - Modified
- `client/src/components/Stories/ChapterReader/ParagraphCommentLayer.jsx` - Created, modified multiple times
- `client/src/components/Stories/ChapterReader/ChapterCommentCard.jsx` - Created
- `client/src/components/Stories/ChapterReader/CommentPanel.jsx` - Created
- `client/src/components/Stories/ChapterReader/ChapterReader.jsx` - Modified
- `client/src/components/Stories/ChapterReader/ChapterReader.css` - Modified extensively
- `server/sql/stories.sql` - Modified (added FK constraint)

The pending/current issue is the flickering badge that can't be clicked. The approach should be to always render all badge anchors in the DOM (not conditionally mount/unmount based on hover) and use CSS classes to control visibility. This avoids the mount/unmount cycle that causes flicker.

Summary:
1. Primary Request and Intent:
   The user asked to implement the frontend UI for paragraph-level comments in a Chapter Reader component for their iskrib_v3 project (a writing platform). The backend (database, API endpoints, services, client API functions) already existed. The implementation needed: comment badges on paragraphs, a slide-in comment panel, React Query hooks, and full dark mode support. After initial implementation, the user asked for visual polish using the `/frontend-design` skill to make it "elegant and delightful" with proper dark mode visibility. Subsequently, the user reported several bugs: badges not appearing, badges disappearing on hover, a Supabase FK relationship error, and badge flickering preventing clicks.

2. Key Technical Concepts:
   - React + Vite frontend with Lexical rich text editor for chapter content
   - Supabase (PostgreSQL) backend with PostgREST join syntax `users(...)`
   - React Query (`@tanstack/react-query`) for data fetching and caching with optimistic updates
   - Framer Motion for animations (spring transitions, AnimatePresence)
   - MutationObserver to detect when Lexical renders `.editor-paragraph` elements
   - DOM event listeners (`mouseenter`/`mouseleave`) attached to paragraph elements for hover detection
   - Debounced hover state with `leaveTimerRef` to prevent premature badge removal
   - CSS variables for light/dark theme support (`--bg-glass`, `--accent-amber`, `--bg-selection`, etc.)
   - Glass morphism (`backdrop-filter: blur`) for badge styling
   - Foreign key relationships: `auth.users` vs `public.users` in Supabase PostgREST

3. Files and Code Sections:

   - **`client/src/components/Stories/hooks/useStoryData.js`**
     - Added two query hooks for comment data fetching
     - Added imports: `getChapterComments`, `getChapterCommentCounts` from StoryApi
     ```javascript
     export const useChapterCommentCounts = (chapterId, token) => {
         return useQuery({
             queryKey: ['chapterCommentCounts', chapterId],
             queryFn: () => getChapterCommentCounts(chapterId, token),
             enabled: !!chapterId,
             staleTime: 30000,
             refetchOnWindowFocus: false,
         });
     };

     export const useChapterComments = (chapterId, paragraphIndex, token) => {
         return useQuery({
             queryKey: ['chapterComments', chapterId, paragraphIndex],
             queryFn: () => getChapterComments(chapterId, paragraphIndex, token),
             enabled: !!chapterId && paragraphIndex !== null && paragraphIndex !== undefined,
             staleTime: 30000,
             refetchOnWindowFocus: false,
         });
     };
     ```

   - **`client/src/components/Stories/hooks/useStoryMutations.js`**
     - Added mutation hook for posting comments with cache invalidation
     ```javascript
     export const useAddChapterComment = (token) => {
         const queryClient = useQueryClient();
         return useMutation({
             mutationFn: ({ chapterId, data }) => addChapterComment(token, chapterId, data),
             onSuccess: (_data, { chapterId }) => {
                 queryClient.invalidateQueries({ queryKey: ['chapterComments', chapterId] });
                 queryClient.invalidateQueries({ queryKey: ['chapterCommentCounts', chapterId] });
             },
         });
     };
     ```

   - **`client/src/components/Stories/ChapterReader/ParagraphCommentLayer.jsx`** (CURRENT ISSUE FILE)
     - Created to overlay comment badges on Lexical paragraphs
     - Uses MutationObserver to detect paragraph elements, attaches mouseenter/mouseleave listeners directly to DOM
     - Has debounced hover with `leaveTimerRef` (150ms) but still flickers — this is the active bug
     - Current full code:
     ```javascript
     import { useState, useEffect, useCallback, useRef } from 'react';
     import { motion } from 'framer-motion';

     const CommentBadge = ({ count, onClick, hasComments }) => {
         return (
             <motion.button
                 className={`pcl-badge ${hasComments ? 'pcl-badge-active' : ''}`}
                 onClick={(e) => { e.stopPropagation(); onClick(); }}
                 initial={{ opacity: 0, x: 6 }}
                 animate={{ opacity: 1, x: 0 }}
                 transition={{ duration: 0.2, ease: 'easeOut' }}
             >
                 {hasComments ? (
                     <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor" stroke="none">
                         <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                     </svg>
                 ) : (
                     <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                         <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                     </svg>
                 )}
                 {hasComments && <span className="pcl-badge-count">{count}</span>}
             </motion.button>
         );
     };

     const ParagraphCommentLayer = ({ containerRef, commentCounts, onParagraphClick }) => {
         const [paragraphs, setParagraphs] = useState([]);
         const [hoveredIndex, setHoveredIndex] = useState(null);
         const listenersRef = useRef([]);
         const leaveTimerRef = useRef(null);

         const clearLeaveTimer = useCallback(() => {
             if (leaveTimerRef.current) {
                 clearTimeout(leaveTimerRef.current);
                 leaveTimerRef.current = null;
             }
         }, []);

         const scheduleLeave = useCallback((idx) => {
             clearLeaveTimer();
             leaveTimerRef.current = setTimeout(() => {
                 setHoveredIndex((prev) => prev === idx ? null : prev);
             }, 150);
         }, [clearLeaveTimer]);

         const scanParagraphs = useCallback(() => {
             const container = containerRef.current;
             if (!container) return;
             listenersRef.current.forEach(({ el, enter, leave }) => {
                 el.removeEventListener('mouseenter', enter);
                 el.removeEventListener('mouseleave', leave);
             });
             listenersRef.current = [];
             const elements = container.querySelectorAll('.editor-paragraph');
             const result = [];
             let realIndex = 0;
             elements.forEach((el) => {
                 const text = el.textContent.trim();
                 if (!text) return;
                 const idx = realIndex;
                 el.setAttribute('data-paragraph-index', idx);
                 const fingerprint = text.substring(0, 100);
                 result.push({ index: idx, top: el.offsetTop, height: el.offsetHeight, text, fingerprint });
                 const enter = () => { clearLeaveTimer(); setHoveredIndex(idx); };
                 const leave = () => scheduleLeave(idx);
                 el.addEventListener('mouseenter', enter);
                 el.addEventListener('mouseleave', leave);
                 listenersRef.current.push({ el, enter, leave });
                 realIndex++;
             });
             setParagraphs(result);
         }, [containerRef, clearLeaveTimer, scheduleLeave]);

         useEffect(() => {
             const container = containerRef.current;
             if (!container) return;
             const timer = setTimeout(scanParagraphs, 300);
             const observer = new MutationObserver(() => { scanParagraphs(); });
             observer.observe(container, { childList: true, subtree: true, characterData: true });
             window.addEventListener('resize', scanParagraphs);
             return () => {
                 clearTimeout(timer);
                 clearLeaveTimer();
                 observer.disconnect();
                 window.removeEventListener('resize', scanParagraphs);
                 listenersRef.current.forEach(({ el, enter, leave }) => {
                     el.removeEventListener('mouseenter', enter);
                     el.removeEventListener('mouseleave', leave);
                 });
                 listenersRef.current = [];
             };
         }, [containerRef, scanParagraphs, clearLeaveTimer]);

         const handleBadgeEnter = useCallback(() => { clearLeaveTimer(); }, [clearLeaveTimer]);
         const handleBadgeLeave = useCallback((idx) => { scheduleLeave(idx); }, [scheduleLeave]);

         const counts = commentCounts || {};

         return (
             <div className="pcl-layer">
                 {paragraphs.map((p) => {
                     const count = counts[p.index] || 0;
                     const hasComments = count > 0;
                     const isHovered = hoveredIndex === p.index;
                     if (!isHovered && !hasComments) return null;
                     return (
                         <div key={p.index} className="pcl-badge-anchor" style={{ top: p.top }}
                             onMouseEnter={handleBadgeEnter}
                             onMouseLeave={() => handleBadgeLeave(p.index)}>
                             <CommentBadge count={count} hasComments={hasComments}
                                 onClick={() => onParagraphClick({ paragraphIndex: p.index, fingerprint: p.fingerprint, text: p.text })} />
                         </div>
                     );
                 })}
             </div>
         );
     };
     export default ParagraphCommentLayer;
     ```

   - **`client/src/components/Stories/ChapterReader/ChapterCommentCard.jsx`**
     - Individual comment card with avatar rings (legend gold glow, OG purple glow), threaded replies, matching existing `commentsCards.jsx` patterns
     - Fixed to use `comment.comment` instead of `comment.body` for display text

   - **`client/src/components/Stories/ChapterReader/CommentPanel.jsx`**
     - Slide-in panel: right side on desktop (380px), bottom sheet on mobile (70vh)
     - Features: header with count pill, paragraph preview with amber accent bar, comment list with amber scrollbar, empty state, input area with reply indicator chip, character counter
